// Works fine — only appending
const list = [{ id: 1, name: 'A' }, { id: 2, name: 'B' }];
list.push({ id: 3, name: 'C' }); // index 2 is new — no shift

// Breaks — prepending shifts every index
list.unshift({ id: 4, name: 'D' }); // A was idx=0, now idx=1 — React sees a change

// Breaks — removing from middle shifts indices after removal
list.splice(1, 1); // everything after index 1 shifts up

import { useState } from 'react';

// ✗ Bug: typing in Alice's input then prepending loses the text
function BadCommentList() {
  const [comments, setComments] = useState([
    { id: 1, author: 'Alice' },
    { id: 2, author: 'Bob' },
  ]);

  function prepend() {
    setComments(prev => [{ id: Date.now(), author: 'New' }, ...prev]);
  }

  return (
    <>
      <button onClick={prepend}>Prepend new comment</button>
      <ul>
        {comments.map((c, i) => (
          // Using index i as key
          <li key={i}>
            {c.author}: <textarea placeholder="Reply..." />
          </li>
        ))}
      </ul>
    </>
  );
}

// ✓ Fix: use stable id
{comments.map(c => (
  <li key={c.id}>
    {c.author}: <textarea placeholder="Reply..." />
  </li>
))}

import { AnimatePresence, motion } from 'framer-motion';

// ✗ Wrong: exit animation plays on last item when first is removed
function BadAnimatedList({ items }) {
  return (
    <AnimatePresence>
      {items.map((item, i) => (
        <motion.li
          key={i}           // ← index key
          exit={{ opacity: 0, height: 0 }}
        >
          {item.name}
        </motion.li>
      ))}
    </AnimatePresence>
  );
}

// ✓ Correct: exit animation on the actually-removed item
function GoodAnimatedList({ items }) {
  return (
    <AnimatePresence>
      {items.map(item => (
        <motion.li
          key={item.id}     // ← stable id
          exit={{ opacity: 0, height: 0 }}
        >
          {item.name}
        </motion.li>
      ))}
    </AnimatePresence>
  );
}

function ProductCard({ product }) {
  const [details, setDetails] = useState(null);

  useEffect(() => {
    // With index keys, this fires for EVERY card after a prepend
    // because the component instance at each position gets a new product prop
    fetchProductDetails(product.id).then(setDetails);
  }, [product.id]);

  return <div>{product.name}: {details?.description}</div>;
}

// In the parent:
// ✗ Causes N fetches on prepend
{products.map((p, i) => <ProductCard key={i} product={p} />)}

// ✓ Each ProductCard instance owns a stable slot; only new ones fetch
{products.map(p => <ProductCard key={p.id} product={p} />)}

function SearchableList({ items }) {
  const [query, setQuery] = useState('');

  const results = items.filter(i =>
    i.name.toLowerCase().startsWith(query.toLowerCase())
  );

  return (
    <>
      <input
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Filter..."
      />
      <ul>
        {/* ✗ If results change order, items with inputs lose focus */}
        {results.map((item, i) => (
          <li key={i}>
            <input type="checkbox" /> {item.name}
          </li>
        ))}

        {/* ✓ Stable key preserves the checkbox's DOM node and state */}
        {results.map(item => (
          <li key={item.id}>
            <input type="checkbox" /> {item.name}
          </li>
        ))}
      </ul>
    </>
  );
}

