import { useState } from 'react';

function NoteList() {
  const [notes, setNotes] = useState([]);

  function addNote(text) {
    setNotes(prev => [
      ...prev,
      { id: crypto.randomUUID(), text }, // ID created once per note
    ]);
  }

  return (
    <ul>
      {notes.map(n => <li key={n.id}>{n.text}</li>)}
    </ul>
  );
}

