import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { CommentList } from './CommentList';

test('input value stays with its item after prepend', async () => {
  const items = [{ id: 1, author: 'Alice' }, { id: 2, author: 'Bob' }];
  const { rerender } = render(<CommentList items={items} />);

  // Type into Alice's textarea (first in list)
  const textareas = screen.getAllByRole('textbox');
  await userEvent.type(textareas[0], 'Hello from Alice');

  // Prepend a new item
  const newItems = [{ id: 3, author: 'Carol' }, ...items];
  rerender(<CommentList items={newItems} />);

  // Alice should now be at index 1 but her typed value must follow her
  const updatedTextareas = screen.getAllByRole('textbox');
  expect(updatedTextareas[0]).toHaveValue('');              // Carol's input — empty
  expect(updatedTextareas[1]).toHaveValue('Hello from Alice'); // Alice's — preserved
});

// React Strict Mode (wraps your app in development)
import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';

createRoot(document.getElementById('root')).render(
  <StrictMode>
    <App />
  </StrictMode>
);
// Strict Mode double-invokes useEffect — index-key bugs with effects
// become obvious because fetchProductDetails(id) fires 2× for each
// item after a reorder, making network waterfalls visible.

function SortableRows({ rows }) {
  const [sortAsc, setSortAsc] = useState(true);

  const sorted = [...rows].sort((a, b) =>
    sortAsc
      ? a.name.localeCompare(b.name)
      : b.name.localeCompare(a.name)
  );

  return (
    <>
      <button onClick={() => setSortAsc(v => !v)}>
        Sort {sortAsc ? 'Z→A' : 'A→Z'}
      </button>
      <table>
        <tbody>
          {sorted.map((row, i) => (
            // ✗ Every cell updated on sort — no DOM reuse
            <tr key={i}><td>{row.name}</td><td>{row.score}</td></tr>
          ))}
          {sorted.map(row => (
            // ✓ React moves <tr> nodes; no content patches needed
            <tr key={row.id}><td>{row.name}</td><td>{row.score}</td></tr>
          ))}
        </tbody>
      </table>
    </>
  );
}

import { FixedSizeList } from 'react-window';

// ✗ Index key: recycled rows show wrong data as user scrolls
const BadRow = ({ index, style, data }) => (
  <div style={style} key={index}>{data[index].name}</div>
);

// ✓ Stable ID: virtual rows map to their data item correctly
const GoodRow = ({ index, style, data }) => {
  const item = data[index];
  return (
    <div style={style} key={item.id}>{item.name}</div>
  );
};

function VirtualTable({ rows }) {
  return (
    <FixedSizeList
      height={400}
      itemCount={rows.length}
      itemSize={40}
      itemData={rows}
    >
      {GoodRow}
    </FixedSizeList>
  );
}
